import { readFileSync } from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const packageRoot = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..');
const brandingPath = path.join(packageRoot, 'branding.json');

// Canonical brand defaults. Used as the fallback when branding.json is absent
// (a fresh checkout — the file is generated by scripts/ensure-branding.mjs and
// intentionally not committed) and as the seed values for that generator. Keep
// these in sync with the `||` chains in BRAND below.
export const DEFAULT_BRAND = Object.freeze({
  productName: 'AgentCli',
  productNameShort: 'AgentCli',
  stylizedName: 'AgentCli',
  cliCommand: 'agentcli',
  npmPackage: '@yancyyu/agentcli',
  runtimeBridgeName: 'hermit-bridge',
  authAccountLabel: 'AgentCli 用户',
  authProviderName: 'AgentCli',
  defaultLocalHomeName: '.hermit',
  githubRepo: 'yancyyu/agentcli',
  publicDocsUrl: 'https://yancyyu.github.io/agentcli/',
});

function readBrandConfig() {
  try {
    const parsed = JSON.parse(readFileSync(brandingPath, 'utf-8'));
    return parsed && typeof parsed === 'object' ? parsed : {};
  } catch {
    // branding.json is generated, not committed. Falling back to DEFAULT_BRAND
    // keeps a fresh checkout bootable instead of crashing at import time.
    return {};
  }
}

const rawBrand = readBrandConfig();

export const BRAND = Object.freeze({
  productName: rawBrand.productName || DEFAULT_BRAND.productName,
  productNameShort:
    rawBrand.productNameShort || rawBrand.productName || DEFAULT_BRAND.productNameShort,
  stylizedName: rawBrand.stylizedName || rawBrand.productName || DEFAULT_BRAND.stylizedName,
  cliCommand: rawBrand.cliCommand || DEFAULT_BRAND.cliCommand,
  npmPackage: rawBrand.npmPackage || DEFAULT_BRAND.npmPackage,
  runtimeBridgeName: rawBrand.runtimeBridgeName || DEFAULT_BRAND.runtimeBridgeName,
  authAccountLabel:
    rawBrand.authAccountLabel ||
    `${rawBrand.stylizedName || DEFAULT_BRAND.stylizedName} 用户`,
  authProviderName:
    rawBrand.authProviderName || rawBrand.stylizedName || DEFAULT_BRAND.authProviderName,
  defaultLocalHomeName: rawBrand.defaultLocalHomeName || DEFAULT_BRAND.defaultLocalHomeName,
  githubRepo: rawBrand.githubRepo || DEFAULT_BRAND.githubRepo,
  publicDocsUrl: rawBrand.publicDocsUrl || DEFAULT_BRAND.publicDocsUrl,
});

export function brandLogPrefix() {
  return `[${BRAND.stylizedName}]`;
}

export function brandCommand(args = '') {
  return [BRAND.cliCommand, args].filter(Boolean).join(' ');
}
